    <h3 style="font-size: 0.95rem; letter-spacing: 1px; text-transform: uppercase; color: #6B6B6B; margin-bottom: 0.75rem;">
      The Principle Behind This Design
    </h3>
    <div style="color: #3A3A3A; line-height: 1.65; font-size: 1.05rem;">
      {{ product.metafields.custom.principle_tie_in }}
    </div>
  </div>
{% endif %}
